#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char S[5005]; scanf("%s", S);
        char R[5005];
        for (int i = 0; i < N; ++i) R[i] = S[N-1-i];
        R[N] = '\0';
        int *prev = (int*)calloc(N+1, sizeof(int));
        int *cur  = (int*)calloc(N+1, sizeof(int));
        int ans = 0;
        for (int i = 1; i <= N; ++i) {
            for (int j = 1; j <= N; ++j) {
                if (S[i-1] == R[j-1]) cur[j] = prev[j-1] + 1;
                else cur[j] = max(prev[j], cur[j-1]);
                if (i + j <= N && cur[j] > ans) ans = cur[j];
            }
            int *tmp = prev; prev = cur; cur = tmp; // reuse rows
        }
        free(prev); free(cur);
        printf("%d\n", ans);
    }
    return 0;
}

